import { spawn } from "node:child_process";
import { mkdtempSync, rmSync, writeFileSync } from "node:fs";
import http from "node:http";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { fileURLToPath } from "node:url";
import { afterAll, afterEach, beforeAll, describe, expect, it } from "vitest";
// pushActivity re-execs itself detached and exits, so it can't be unit-tested
// in-process (process.exit would kill the test runner). These tests spawn the
// real command as a subprocess and assert the POST still lands after the
// foreground (parent) process has already returned — the fire-and-forget
// contract the agent depends on.
const SOURCE_PATH = fileURLToPath(new URL("./pushActivity.ts", import.meta.url));
const TEST_SESSION_ID = "1ea32041-ce13-428f-b394-f0f9ecb46acf";
describe("runPushActivity (fire-and-forget)", () => {
    let server;
    let baseUrl;
    let requestLog = [];
    let tmpDir;
    let entryPath;
    // Delay the server response so a worker that completes its POST does so well
    // after the foreground process has exited — proving the write is detached.
    let serverDelayMs = 0;
    beforeAll(async () => {
        server = http.createServer((req, res) => {
            let body = "";
            req.on("data", (chunk) => {
                body += chunk;
            });
            req.on("end", () => {
                requestLog.push({
                    method: req.method ?? "",
                    url: req.url ?? "",
                    headers: req.headers,
                    body,
                });
                setTimeout(() => {
                    res.writeHead(200, { "Content-Type": "application/json" });
                    res.end(JSON.stringify({ id: "1-0" }));
                }, serverDelayMs);
            });
        });
        await new Promise((resolve) => {
            server.listen(0, "127.0.0.1", resolve);
        });
        const addr = server.address();
        baseUrl = `http://127.0.0.1:${addr.port}`;
        // A real entry file is required because the worker re-execs `process.argv[1]`.
        tmpDir = mkdtempSync(join(tmpdir(), "push-activity-"));
        entryPath = join(tmpDir, "entry.mjs");
        writeFileSync(entryPath, `import { runPushActivity } from ${JSON.stringify(SOURCE_PATH)}\n` +
            `runPushActivity().catch((err) => { console.error(err); process.exit(1) })\n`);
    });
    afterAll(async () => {
        rmSync(tmpDir, { recursive: true, force: true });
        await new Promise((resolve, reject) => {
            server.close((err) => (err ? reject(err) : resolve()));
        });
    });
    afterEach(() => {
        requestLog = [];
        serverDelayMs = 0;
    });
    function runForeground(args) {
        const startedAt = Date.now();
        const child = spawn(process.execPath, [entryPath, ...args], {
            stdio: ["ignore", "ignore", "inherit"],
            env: {
                ...process.env,
                // Propagates to the detached worker (which re-execs via `node`), so it
                // too can load the .ts source through tsx.
                NODE_OPTIONS: "--import tsx",
                BITFAB_SERVICE_URL: baseUrl,
                BITFAB_API_KEY: "test-api-key",
            },
        });
        return new Promise((resolve, reject) => {
            child.on("error", reject);
            child.on("close", (code) => resolve({ exitCode: code ?? -1, durationMs: Date.now() - startedAt }));
        });
    }
    async function waitForRequests(count, timeoutMs = 5000) {
        const deadline = Date.now() + timeoutMs;
        while (requestLog.length < count && Date.now() < deadline) {
            await new Promise((r) => setTimeout(r, 25));
        }
    }
    it("returns without waiting on the POST, then the detached worker delivers it", async () => {
        // The server holds every response for 2s. A blocking implementation would
        // make the foreground process take >2s; fire-and-forget returns in ~startup
        // time and the worker completes the POST out-of-band afterward.
        serverDelayMs = 2000;
        const { exitCode, durationMs } = await runForeground([
            TEST_SESSION_ID,
            "started",
            "Building dataset",
        ]);
        expect(exitCode).toBe(0);
        expect(durationMs).toBeLessThan(1500);
        await waitForRequests(1);
        expect(requestLog).toHaveLength(1);
        const req = requestLog[0];
        expect(req.method).toBe("POST");
        expect(req.url).toBe("/api/studio/events");
        expect(req.headers.authorization).toBe("Bearer test-api-key");
        expect(JSON.parse(req.body)).toEqual({
            session: TEST_SESSION_ID,
            type: "agent:activity",
            data: {
                action: "started",
                tool: "assistant",
                displayName: "Building dataset",
            },
        });
    });
    it("exits non-zero without POSTing when the action is invalid", async () => {
        const { exitCode } = await runForeground([
            TEST_SESSION_ID,
            "bogus",
            "Bad action",
        ]);
        // Invalid action is a usage error -> exit 1, no spawn, no POST.
        expect(exitCode).toBe(1);
        await waitForRequests(1, 500);
        expect(requestLog).toHaveLength(0);
    });
});
